Part.Source:
for Each order PdvRandon
	Where PdvRandon = &PdvRandon //PRA SABER SE É UM PDV VALIDO

	&EmpCod = EmpCod
	&FilCod = PdvFilCod
	if PdvFilCod.IsEmpty() or PdvFilCod.IsNull()
		PdvFilCod = 1
		&FilCod = 1
		Commit
	Endif


	Exit
When none
	&sdtGetConfig.Sts = 'E998'
	&sdtGetConfig.Msg = 'PDV Não localizado'

	Return
EndFor

&sdtGetConfig.Sts = 'J200'
&sdtGetConfig.Msg = 'Sucesso Conexao'

//TABELA FILIAL
For Each Order EmpCod, FilCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	&sdtGetConfig.EmpCod = EmpCod
	&sdtGetConfig.FilCod = FilCod
	&sdtGetConfig.FilRaz = FilRaz
	&sdtGetConfig.FilCnpj = FilCpj
	&sdtGetConfig.FilInsEst = FilInsEst

	&sdtGetConfig.FilFan = FilFan
	&sdtGetConfig.FilLog = FilLog
	&sdtGetConfig.FilNro = FilNro
	&sdtGetConfig.FilCpl = FilCpl
	&sdtGetConfig.FilBai = FilBai
	&sdtGetConfig.FilCep = FilCep

	&sdtGetConfig.TabCod = FilBalTabCod
	&sdtGetConfig.TabPrmCod = FilBalTabPrmCod
	&sdtGetConfig.TabColCod = FilBalTabColCod
	&sdtGetConfig.FilCidCod = FilCidCod
	&sdtGetConfig.FilCidNom = FilCidNom
	&sdtGetConfig.FilCidUfeCod = FilCidUfeCod
	&sdtGetConfig.EmpDirVirPdv = EmpDirVirPdv

	&sdtGetConfig.FilFonNum = FilFonNum
	&sdtGetConfig.FilEml = FilEml
	&sdtGetConfig.TConCod = FilTConCod

	&sdtGetConfig.EmpCodSec = EmpCodSec
	getVencimento.Call(EmpCod, EmpChv, &JaspiVarchar, &VencimentoData, &EmPCodSec, &QtdDias)

	&sdtGetConfig.EmpCodSecDtaTmp = DateToTimestamp.Udp(&VencimentoData)

	&FilTConCod = FilTConCod

	Exit
EndFor

//CONFIG SISTEMA
For Each Order EmpCod, TConCod
	Where EmpCod = &EmpCod
	Where TConCod = &FilTConCod

//	&sdtGetConfig.TCon019 = TCon019 // Cod.Lancamento Orcamento
	&sdtGetConfig.TCon020 = TCon020 // Cliente Padrao a vista

	//&sdtGetConfigConfigs.CodigoConfig = 'TCon039' // Tipo lancamento PDV

	&sdtGetConfig.TCon133 = TCon133	 // Bloqueia Vendas Cliente Débito
	&sdtGetConfig.TCon146 = TCon146 // Valor abertura caixa PDV
	&sdtGetConfig.TCon149 = TCon149 // Permitir Abrir caixa com valor Personalizado

	//&sdtGetConfigConfigs.CodigoConfig = 'TCon170' // PDV, Emitir NF Automatica Cartao
	//&sdtGetConfigConfigs.CodigoConfig = TCon171 // PDV, Emitir NF Automatica PIX
	//&sdtGetConfigConfigs.CodigoConfig = TCon172 //PDV, Emitir NF Automatica Dinheiro
	//&sdtGetConfigConfigs.ValorConfig = TCon173.Trim() //PDV, Emitir NF Automatica Cheque
	//&sdtGetConfig.TCon174 = TCon174 //PDV, Emitir NF Automatica Crediario com CPF

	&sdtGetConfig.TCon176 = TCon176 //PDV Fecha Caixa - Imprimir Resumo Dinheiro/TEF
	&sdtGetConfig.TCon177 = TCon177 //PDV Fecha caixa - Imprimir Resumo Credito/Debito/Cheque/Pix

	&sdtGetConfig.TCon186 = TCon186 //Solicitar Senha Cancelar Item
	&sdtGetConfig.TCon187 = TCon187 //Solicitar Senha Venda em aberto
	&sdtGetConfig.TCon188 = TCon188 //Solicitar Senha Trocar Cliente Pedido	
	&sdtGetConfig.TCon189 = TCon189 //Solicitar Senha Saldo Devedor	
	&sdtGetConfig.TCon190 = TCon190 //Solicitar Senha quantidade/valores Manuais
	&sdtGetConfig.TCon191 = TCon191 //Solicitar Senha Descontos maiores que.
	&sdtGetConfig.TCon192 = TCon192 //Solicitar Senha Venda Funcionario


	Exit
EndFor

